#### `src/lib/core/scaleStore.ts`
This is the heart of the application—the direct software implementation of the UHT framework's logarithmic mapping, combining D3.js and Svelte's reactive stores.

```typescript
import { writable } from 'svelte/store';
import { scaleLog } from 'd3-scale';
import { MIN_SCALE, MAX_SCALE } from './data';

// Architectural Philosophy (Section 4.1) & System Data Flow (Section 4.2)
// This store is the "Scaling Logic (D3.js)" and "State (Svelte)" combined.
// It acts as the central hub for managing the application's logarithmic state.

// The reactive store holding the current scale in meters.
// Any component can subscribe to this to get live updates.
export const currentScale = writable(1); // Start at human scale (1 meter)

// This is the direct software implementation of the logarithmic mapping function.
// It maps the vast, non-linear domain of physical scales (our model)
// to a linear range (our UI, e.g., a slider from 0 to 100).
export const scaleController = scaleLog()
	.domain([MIN_SCALE, MAX_SCALE])
	.range([0, 100])
	.clamp(true);

// Function to update the global scale using the linear value from a UI element.
// This is the "Logarithmic Calculation" step in the data flow.
export function setScaleFromLinear(linearValue: number) {
	const newScale = scaleController.invert(linearValue);
	currentScale.set(newScale);
}

// Initialize the store to the starting scale
setScaleFromLinear(scaleController(1));
```

#### `src/lib/components/CosmicCanvas.svelte`
This is the "Rendering Engine (Three.js)" and "Visual Perceptualization Engine." It subscribes to the `scaleStore` and updates the camera to create the zoom effect.

```svelte
<script lang="ts">
	import { onMount } from 'svelte';
	import * as THREE from 'three';
	import { currentScale } from '$lib/core/scaleStore';
	import { cosmicData } from '$lib/core/data';
	import particleTexture from '$lib/assets/particle.png';

	let canvas: HTMLCanvasElement;

	onMount(() => {
		// --- Scene Setup ---
		const scene = new THREE.Scene();
		const camera = new THREE.OrthographicCamera(-1, 1, 1, -1, 0.1, 100);
		camera.position.z = 5;

		const renderer = new THREE.WebGLRenderer({ canvas, antialias: true });
		renderer.setPixelRatio(window.devicePixelRatio);
		renderer.setSize(window.innerWidth, window.innerHeight);

		// --- Object Creation (Placeholder Assets) ---
		const loader = new THREE.TextureLoader();
		const texture = loader.load(particleTexture);
		const material = new THREE.SpriteMaterial({ map: texture, color: 0xffffff });

		cosmicData.forEach((obj) => {
			const sprite = new THREE.Sprite(material);
			// We store the object's true scale in its userdata for later use
			sprite.userData.scale_m = obj.scale_m;
			scene.add(sprite);
		});

		// --- Resizing Logic ---
		function onWindowResize() {
			const aspect = window.innerWidth / window.innerHeight;
			camera.left = -aspect;
			camera.right = aspect;
			camera.updateProjectionMatrix();
			renderer.setSize(window.innerWidth, window.innerHeight);
		}
		window.addEventListener('resize', onWindowResize);

		// --- Core UHT Logic: Connecting State to Visuals ---
		// This is the "Scene Update" step (Section 4.2). The animation loop
		// subscribes to the Svelte store and updates the Three.js scene.
		const unsubscribe = currentScale.subscribe((scale) => {
			// Update camera zoom to reflect the new scale
			camera.zoom = 1 / (scale * 2); // The '2' is an arbitrary factor for nice framing
			camera.updateProjectionMatrix();

			// Perform the critical culling and scaling operation
			scene.children.forEach((child) => {
				if (child instanceof THREE.Sprite) {
					const objScale = child.userData.scale_m;
					// Make the sprite visible only when we are "near" its scale
					child.visible = Math.abs(Math.log10(scale) - Math.log10(objScale)) < 1;
					// Scale the sprite so it appears roughly the same size on screen
					child.scale.set(objScale, objScale, 1);
				}
			});
		});

		// --- Animation Loop ---
		function animate() {
			requestAnimationFrame(animate);
			renderer.render(scene, camera);
		}
		animate();

		// Cleanup on component destruction
		return () => {
			window.removeEventListener('resize', onWindowResize);
			unsubscribe();
		};
	});
</script>

<canvas bind:this={canvas}></canvas>

<style>
