	}
</style>
```

#### `src/lib/components/ZoomSlider.svelte`
This Svelte component provides the "Logarithmic Slider" UI mechanic mentioned in your document.

```svelte
<script lang="ts">
	import { scaleController, setScaleFromLinear } from '$lib/core/scaleStore';

	// The slider's value is a linear representation (0-100)
	let sliderValue = scaleController(1); // Initialize to human scale

	function handleInput(event: Event) {
		const target = event.target as HTMLInputElement;
		sliderValue = Number(target.value);
		// This triggers the UHT data flow pipeline
		setScaleFromLinear(sliderValue);
	}
</script>

<div class="slider-container">
	<span class="label">Planck Length</span>
	<input
		type="range"
		min="0"
		max="100"
		step="0.01"
		bind:value={sliderValue}
		on:input={handleInput}
	/>
	<span class="label">Observable Universe</span>
</div>

<style>
